INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-namokar-mantra-introduction', 'literature', 'namokar-mantra-introduction', 'Namokar Mantra introduction', 'The Namokar Mantra is a foundational Jain prayer often used as a starting point for humility, reverence, and calm reflection.', 'literature The Namokar Mantra is a foundational Jain prayer often used as a starting point for humility, reverence, and calm reflection. णमोकार मंत्र जैन परंपरा में विनय, श्रद्धा और शांत मनन का एक प्रमुख प्रारंभिक पाठ है। This entry introduces the spirit, use, and family learning context of the Namokar Mantra without reproducing long liturgical text. It helps new readers understand that the prayer centers on reverence for ideal spiritual qualities. यह परिचय लंबे पाठ को उद्धृत किए बिना णमोकार मंत्र के भाव, उपयोग और पारिवारिक सीख के संदर्भ को सरल रूप में समझाता है। नए पाठकों के लिए यह जानना उपयोगी है कि मंत्र का केंद्र आदर्श गुणों के प्रति नम्र वंदना है। Scripture Beginner Prayer Guide namokar mantra,navkar mantra,prayer,introduction,णमोकार मंत्र', '/article.html?type=literature&slug=namokar-mantra-introduction', 'Scripture', 'namokar mantra,navkar mantra,prayer,introduction,णमोकार मंत्र', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-meaning-of-ahimsa', 'literature', 'meaning-of-ahimsa', 'Meaning of Ahimsa', 'Ahimsa is not only about external restraint but also about care in thought, speech, and conduct.', 'literature Ahimsa is not only about external restraint but also about care in thought, speech, and conduct. अहिंसा केवल बाहरी आचरण नहीं, बल्कि विचार, वचन और व्यवहार में सावधानी का अभ्यास भी है। This entry explains why Jain tradition treats Ahimsa as a deep ethical and spiritual discipline. For families, children, and new learners, it offers a gentle understanding of how non-violence connects with compassion, care, and self-awareness. यह परिचय बताता है कि जैन परंपरा में अहिंसा को एक गहरे नैतिक और आध्यात्मिक अनुशासन के रूप में क्यों देखा जाता है। परिवार, बच्चों और नए सीखने वालों के लिए यह समझना उपयोगी है कि अहिंसा दया, सावधानी और आत्म-जागरूकता से जुड़ी हुई है। Philosophy Overview ahimsa,non violence,philosophy,beginner,अहिंसा', '/article.html?type=literature&slug=meaning-of-ahimsa', 'Philosophy', 'ahimsa,non violence,philosophy,beginner,अहिंसा', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-aparigraha-introduction', 'literature', 'aparigraha-introduction', 'Aparigraha introduction', 'Aparigraha introduces the value of limited possession, balanced living, and awareness around attachment.', 'literature Aparigraha introduces the value of limited possession, balanced living, and awareness around attachment. अपरिग्रह का भाव सीमित संग्रह, संतुलित जीवन और आसक्ति को समझने का मार्ग खोलता है। Many Jain families explain Aparigraha not only through fewer possessions, but through simplicity of mind and reduced attachment. This entry focuses on the principle''s practical relevance in modern life. कई जैन परिवार अपरिग्रह को केवल वस्तुओं की संख्या से नहीं, बल्कि मन की सरलता और सीमित अपेक्षाओं से भी जोड़कर समझाते हैं। यह प्रविष्टि आधुनिक जीवन में इस सिद्धांत की सरल उपयोगिता पर केंद्रित है। Philosophy Ethics aparigraha,ethics,simplicity,beginner,अपरिग्रह', '/article.html?type=literature&slug=aparigraha-introduction', 'Philosophy', 'aparigraha,ethics,simplicity,beginner,अपरिग्रह', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-anekantavada-introduction', 'literature', 'anekantavada-introduction', 'Anekantavada introduction', 'Anekantavada invites humility in viewpoint, respectful dialogue, and a many-sided understanding of truth.', 'literature Anekantavada invites humility in viewpoint, respectful dialogue, and a many-sided understanding of truth. अनेकांतवाद हमें दृष्टिकोण की विनम्रता, संवाद और सत्य के बहु-पक्षीय समझ की ओर ले जाता है। This entry presents Anekantavada as an accessible doorway rather than a complete philosophical treatment. It helps families, youth, and new readers understand why humility and care matter when viewpoints differ. यह प्रविष्टि अनेकांतवाद को दार्शनिक गहराई के संपूर्ण पाठ के रूप में नहीं, बल्कि एक सरल प्रवेश-द्वार के रूप में प्रस्तुत करती है। इसका उद्देश्य परिवारों, युवाओं और नए पाठकों को समझाना है कि मतभेद के बीच भी विनम्रता और सावधानी क्यों महत्वपूर्ण है। Philosophy Overview anekantavada,many sided truth,dialogue,philosophy,अनेकांतवाद', '/article.html?type=literature&slug=anekantavada-introduction', 'Philosophy', 'anekantavada,many sided truth,dialogue,philosophy,अनेकांतवाद', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-basic-jain-principles', 'literature', 'basic-jain-principles', 'Basic Jain principles', 'Ideas such as Ahimsa, truthfulness, restraint, compassion, and self-discipline shape the Jain way of life.', 'literature Ideas such as Ahimsa, truthfulness, restraint, compassion, and self-discipline shape the Jain way of life. अहिंसा, सत्य, संयम, करुणा और आत्म-अनुशासन जैसे विचार जैन जीवन दृष्टि को दिशा देते हैं। This page offers a calm, family-friendly overview of core Jain values. It is meant as a starting point for understanding, conversation, and practice rather than formal doctrinal study. यह पृष्ठ जैन जीवन के प्रमुख मूल्यों का एक शांत और परिवार-उपयोगी परिचय देता है। औपचारिक अध्ययन के स्थान पर यह केवल शुरुआती समझ, चर्चा और अभ्यास के लिए बनाया गया है। Scripture Overview jain principles,ahimsa,truth,restraint,basics', '/article.html?type=literature&slug=basic-jain-principles', 'Scripture', 'jain principles,ahimsa,truth,restraint,basics', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-jain-stories-for-children', 'literature', 'jain-stories-for-children', 'Jain stories for children', 'Simple stories can help children understand kindness, restraint, humility, and respect for life.', 'literature Simple stories can help children understand kindness, restraint, humility, and respect for life. सरल कथाएँ बच्चों को दया, संयम, विनम्रता और जीवों के प्रति सम्मान समझाने में मदद कर सकती हैं। This entry is a starter guide for families and teachers who want to use Jain stories in value-based conversations with children. It focuses on learning direction rather than long narrative text. यह प्रविष्टि परिवारों और शिक्षकों के लिए एक परिचयात्मक मार्गदर्शिका है कि जैन कथाओं का उपयोग बच्चों से मूल्य-आधारित बातचीत में कैसे किया जा सकता है। इसमें लंबे पाठ नहीं, बल्कि सीख की दिशा पर ध्यान दिया गया है। Kids Stories Stories and Values children,kids stories,values,family learning,बच्चों की कथाएँ', '/article.html?type=literature&slug=jain-stories-for-children', 'Kids Stories', 'children,kids stories,values,family learning,बच्चों की कथाएँ', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-paryushan-reading-guide', 'literature', 'paryushan-reading-guide', 'Paryushan reading guide', 'A simple guide to reading themes of reflection, forgiveness, study, and restraint during Paryushan.', 'literature A simple guide to reading themes of reflection, forgiveness, study, and restraint during Paryushan. पर्युषण के दिनों में अध्ययन, आत्मचिंतन, क्षमा और संयम से जुड़े विषयों को कैसे पढ़ें, इसका सरल मार्गदर्शन। Rather than prescribing formal observance, this guide suggests reading directions for the Paryushan period. Families and traditions may follow different practices, so local guidance remains valuable for stricter observance. यह सामग्री पर्व-विशेष की औपचारिक विधि बताने के बजाय अध्ययन की दिशा सुझाती है। अलग-अलग परिवार और परंपराएँ भिन्न पद्धतियाँ अपनाती हैं, इसलिए गहरे पालन के लिए स्थानीय मार्गदर्शन उपयोगी रहेगा। Festival Reading Guide paryushan,festival,reading guide,forgiveness,पर्युषण', '/article.html?type=literature&slug=paryushan-reading-guide', 'Festival', 'paryushan,festival,reading guide,forgiveness,पर्युषण', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-samvatsari-reflection-guide', 'literature', 'samvatsari-reflection-guide', 'Samvatsari reflection guide', 'A starter guide centered on forgiveness, self-review, and quiet reflection for Samvatsari.', 'literature A starter guide centered on forgiveness, self-review, and quiet reflection for Samvatsari. संवत्सरी के अवसर पर क्षमापना, आत्म-परीक्षण और शांत मनन के भावों पर केंद्रित एक शुरुआती मार्गदर्शिका। This guide offers a respectful starting point for reflection and family conversation rather than formal ritual instruction. Users are encouraged to honor local tradition, teacher guidance, and family practice. यह सामग्री औपचारिक अनुष्ठानों के स्थान पर मनन की भाषा और पारिवारिक बातचीत का एक विनम्र प्रारंभ देती है। उपयोगकर्ताओं को स्थानीय परंपरा, आचार्य मार्गदर्शन या परिवार की विधि का सम्मान करने की सलाह दी जाती है। Festival Reflection Guide samvatsari,forgiveness,reflection,festival,संवत्सरी', '/article.html?type=literature&slug=samvatsari-reflection-guide', 'Festival', 'samvatsari,forgiveness,reflection,festival,संवत्सरी', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-tattvartha-sutra-introduction', 'literature', 'tattvartha-sutra-introduction', 'Tattvartha Sutra introduction', 'Tattvartha Sutra is often seen as an important doorway into a structured understanding of Jain philosophy.', 'literature Tattvartha Sutra is often seen as an important doorway into a structured understanding of Jain philosophy. तत्त्वार्थ सूत्र जैन दर्शन के कुछ मूल विचारों को व्यवस्थित ढंग से समझने का एक महत्वपूर्ण प्रवेश-द्वार माना जाता है। This introduction explains why Tattvartha Sutra is considered significant and how a new student may begin approaching it. For deeper interpretation and traditional commentary, qualified guidance remains helpful. यह परिचय पाठकों को बताता है कि तत्त्वार्थ सूत्र का अध्ययन क्यों महत्वपूर्ण माना जाता है और नए विद्यार्थी इसमें प्रवेश कैसे लें। गहन शब्दार्थ और पारंपरिक व्याख्या के लिए शिक्षक मार्गदर्शन उपयोगी रहेगा। Philosophy Sutra tattvartha sutra,sutra,philosophy,beginner,तत्त्वार्थ सूत्र', '/article.html?type=literature&slug=tattvartha-sutra-introduction', 'Philosophy', 'tattvartha sutra,sutra,philosophy,beginner,तत्त्वार्थ सूत्र', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-agamas-overview', 'literature', 'agamas-overview', 'Agamas overview', 'This calm overview helps readers understand the Agamas as part of a broader Jain scriptural tradition.', 'literature This calm overview helps readers understand the Agamas as part of a broader Jain scriptural tradition. आगम साहित्य को एक व्यापक जैन शास्त्रीय परंपरा के रूप में समझने के लिए यह शांत प्रारंभिक अवलोकन उपयोगी है। Before entering detailed textual study, it helps to understand what kinds of material the word Agamas points to. This entry gives new readers a careful direction rather than a final doctrinal conclusion. विस्तृत शास्त्रीय अध्ययन से पहले यह जानना उपयोगी है कि आगम शब्द किस प्रकार के साहित्य की ओर संकेत करता है। यह प्रविष्टि शुरुआती पाठकों को अधिक सुरक्षित और विनम्र दिशा देती है, न कि अंतिम शास्त्रीय निष्कर्ष। Agamas Overview agamas,scripture,overview,text study,आगम', '/article.html?type=literature&slug=agamas-overview', 'Agamas', 'agamas,scripture,overview,text study,आगम', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-bhaktamar-stotra-introduction', 'literature', 'bhaktamar-stotra-introduction', 'Bhaktamar Stotra introduction', 'Bhaktamar Stotra is widely associated with Jain devotional reverence, and an introductory note can help new learners approach it respectfully.', 'literature Bhaktamar Stotra is widely associated with Jain devotional reverence, and an introductory note can help new learners approach it respectfully. भक्तामर स्तोत्र जैन भक्ति परंपरा में व्यापक श्रद्धा से जुड़ा है, और इसे समझने के लिए परिचयात्मक पृष्ठ उपयोगी हो सकता है। This entry focuses on the stotra''s devotional importance and a respectful direction for learning. It does not reproduce long verses or a full text; formal recitation and interpretation should come from trusted traditional sources. यह प्रविष्टि स्तोत्र के महत्व, श्रद्धा-परंपरा और अध्ययन की दिशा पर केंद्रित है। इसमें लंबे श्लोक या पूर्ण पाठ नहीं दिए गए हैं; औपचारिक पाठ और अर्थ के लिए विश्वसनीय पारंपरिक स्रोतों का सहारा लिया जाना चाहिए। Devotional Overview bhaktamar stotra,devotional,stotra,introduction,भक्तामर', '/article.html?type=literature&slug=bhaktamar-stotra-introduction', 'Devotional', 'bhaktamar stotra,devotional,stotra,introduction,भक्तामर', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-literature-jain-symbols-and-their-meaning', 'literature', 'jain-symbols-and-their-meaning', 'Jain symbols and their meaning', 'Understanding Jain symbols can help children, families, and new readers connect visual identity with values and learning.', 'literature Understanding Jain symbols can help children, families, and new readers connect visual identity with values and learning. जैन प्रतीकों को समझना बच्चों, परिवारों और नए पाठकों के लिए धार्मिक पहचान और मूल्यों को जोड़ने का सरल माध्यम हो सकता है। This page explains the educational value of Jain symbols in respectful, general language. Interpretive emphasis may vary across traditions, so it is best used as a starting point for learning. यह पृष्ठ सामान्य और सम्मानपूर्ण भाषा में जैन प्रतीकों के शैक्षिक उपयोग को समझाता है। विभिन्न परंपराओं में व्याख्या का स्वर थोड़ा भिन्न हो सकता है, इसलिए इसे प्रारंभिक अध्ययन सामग्री के रूप में उपयोग करना उचित है। Overview Symbols jain symbols,overview,children,family learning,जैन प्रतीक', '/article.html?type=literature&slug=jain-symbols-and-their-meaning', 'Overview', 'jain symbols,overview,children,family learning,जैन प्रतीक', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-how-jain-values-help-modern-families', 'blogs', 'how-jain-values-help-modern-families', 'How Jain values help modern families', 'Jain values such as compassion, restraint, simplicity, and discipline can help families build a calmer daily life.', 'blogs Jain values such as compassion, restraint, simplicity, and discipline can help families build a calmer daily life. Family life today can feel rushed, but Jain values can create steadiness at home. Gentle speech, timely meals, limited consumption, and short family learning routines can help everyone become more mindful. Each family can begin with small steps that suit its tradition and daily rhythm. Family Life family,values,ahimsa,discipline,home', '/article.html?type=blogs&slug=how-jain-values-help-modern-families', 'Family Life', 'family,values,ahimsa,discipline,home', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-01', '2026-05-20', 3, '2026-05-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-teaching-ahimsa-to-children', 'blogs', 'teaching-ahimsa-to-children', 'Teaching Ahimsa to children', 'Ahimsa becomes easier for children to understand through daily behavior, gentle words, food discipline, and acts of kindness.', 'blogs Ahimsa becomes easier for children to understand through daily behavior, gentle words, food discipline, and acts of kindness. Children usually understand Ahimsa better through examples than through definitions alone. Respect for living beings, gentle language, gratitude for food, and habits that reduce harm are all part of the lesson. Parents and teachers can use stories, questions, and small practices to make the idea natural. Children ahimsa,children,parents,teachers,stories', '/article.html?type=blogs&slug=teaching-ahimsa-to-children', 'Children', 'ahimsa,children,parents,teachers,stories', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-02', '2026-05-20', 3, '2026-05-02');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-preparing-for-paryushan-as-a-family', 'blogs', 'preparing-for-paryushan-as-a-family', 'Preparing for Paryushan as a family', 'Family preparation for Paryushan can include simple planning for routine, food discipline, learning, forgiveness, and reflection.', 'blogs Family preparation for Paryushan can include simple planning for routine, food discipline, learning, forgiveness, and reflection. For many families, Paryushan is a period of reflection and discipline. It helps to plan meals, schedules, readings, and children''s participation in advance. Local sangh guidance and family elders can help shape a meaningful routine. Always verify dates and specific observances with a local Jain calendar. Festivals paryushan,family,forgiveness,calendar,discipline', '/article.html?type=blogs&slug=preparing-for-paryushan-as-a-family', 'Festivals', 'paryushan,family,forgiveness,calendar,discipline', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-03', '2026-05-20', 3, '2026-05-03');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-jain-food-discipline-in-modern-life', 'blogs', 'jain-food-discipline-in-modern-life', 'Jain food discipline in modern life', 'Jain food discipline can still be followed thoughtfully in busy modern life with planning, awareness, and family support.', 'blogs Jain food discipline can still be followed thoughtfully in busy modern life with planning, awareness, and family support. Jain food discipline is not only about what to eat. It is also a practice of awareness and restraint. Families often need to balance home routines, travel, outside food, and children''s needs. Many households follow the discipline in ways shaped by family tradition, health needs, and elder guidance. Food food,discipline,ahimsa,family,travel', '/article.html?type=blogs&slug=jain-food-discipline-in-modern-life', 'Food', 'food,discipline,ahimsa,family,travel', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-04', '2026-05-20', 3, '2026-05-04');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-visiting-a-jain-temple-respectfully', 'blogs', 'visiting-a-jain-temple-respectfully', 'Visiting a Jain temple respectfully', 'Temple visits are more meaningful when done with cleanliness, calmness, humility, and respect for local guidance.', 'blogs Temple visits are more meaningful when done with cleanliness, calmness, humility, and respect for local guidance. A Jain temple is not only a place to see, but a place of reverence and discipline. Before visiting, understand local guidance about dress, cleanliness, food expectations, and photography. For timings, dharamshala, or bhojanshala details, the safest approach is to confirm locally with the temple or trust. Temples temple,visit,discipline,pilgrimage,respect', '/article.html?type=blogs&slug=visiting-a-jain-temple-respectfully', 'Temples', 'temple,visit,discipline,pilgrimage,respect', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-05', '2026-05-20', 3, '2026-05-05');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-building-a-daily-jain-learning-habit', 'blogs', 'building-a-daily-jain-learning-habit', 'Building a daily Jain learning habit', 'A small but steady learning routine can make Jain values more rooted in individual and family life.', 'blogs A small but steady learning routine can make Jain values more rooted in individual and family life. Daily Jain learning does not require long study hours. A few minutes of reading, one thoughtful question, or simple mantra remembrance can be enough to begin. Families can also create one shared weekly learning time and invite children to ask simple questions. Learning learning,daily-practice,family,children,reflection', '/article.html?type=blogs&slug=building-a-daily-jain-learning-habit', 'Learning', 'learning,daily-practice,family,children,reflection', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-06', '2026-05-20', 3, '2026-05-06');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-why-source-verification-matters-in-community-resources', 'blogs', 'why-source-verification-matters-in-community-resources', 'Why source verification matters in community resources', 'Source verification is essential for trustworthy scholarship, temple, contact, and support information.', 'blogs Source verification is essential for trustworthy scholarship, temple, contact, and support information. Community platforms remain useful only when their information is verified. Old or incomplete details about scholarships, temple visits, trust contacts, or government resources can cause confusion. That is why correction workflows, review steps, and cautious publishing are important on JainWorld. Community verification,resources,community,trust,corrections', '/article.html?type=blogs&slug=why-source-verification-matters-in-community-resources', 'Community', 'verification,resources,community,trust,corrections', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-07', '2026-05-20', 3, '2026-05-07');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-why-jains-avoid-root-vegetables', 'food', 'why-jains-avoid-root-vegetables', 'Why Jains avoid root vegetables', 'Many Jain families explain avoiding root vegetables through Ahimsa, care for subtle life, and traditional food discipline.', 'food Many Jain families explain avoiding root vegetables through Ahimsa, care for subtle life, and traditional food discipline. Uprooting root vegetables is often associated with greater harm to subtle life forms. Bottle gourd, pumpkin, cabbage, and raw banana are commonly treated as practical alternatives in many homes. root vegetables,ahimsa,food discipline,कंद-मूल', '/article.html?type=food&slug=why-jains-avoid-root-vegetables', 'What not to eat', 'root vegetables,ahimsa,food discipline,कंद-मूल', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-eating-before-sunset', 'food', 'eating-before-sunset', 'Eating before sunset', 'Many Jain families treat eating before sunset as part of time discipline and mindful routine.', 'food Many Jain families treat eating before sunset as part of time discipline and mindful routine. This practice is often linked with restraint, care, and a more disciplined daily rhythm. Earlier meals may also feel easier for digestion and routine planning for many people. sunset meal,daily discipline,evening routine,सूर्यास्त से पहले भोजन', '/article.html?type=food&slug=eating-before-sunset', 'Daily discipline', 'sunset meal,daily discipline,evening routine,सूर्यास्त से पहले भोजन', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-travel-food-checklist', 'food', 'travel-food-checklist', 'Travel food checklist', 'A simple advance checklist can make food discipline more manageable for families during travel.', 'food A simple advance checklist can make food discipline more manageable for families during travel. Dry snacks, fruit, simple home food, and light packed options Plan calmly before travel by checking ingredients, meal timing, and available alternatives. Many families value maintaining awareness and restraint even while traveling. Advance planning can reduce confusion, rushed choices, and unnecessary compromise. travel food,checklist,family travel,यात्रा भोजन', '/article.html?type=food&slug=travel-food-checklist', 'Travel food', 'travel food,checklist,family travel,यात्रा भोजन', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-jain-food-for-children', 'food', 'jain-food-for-children', 'Jain food for children', 'Simple language, family-friendly options, and patient explanation can help children understand Jain food discipline.', 'food Simple language, family-friendly options, and patient explanation can help children understand Jain food discipline. Simple home snacks, fruit, light vegetables, and school-friendly tiffin options Start with small habits and explainable choices rather than rigid instructions. Teaching children kindness, restraint, and awareness around food can become a shared family learning practice. Clear and planned choices can be helpful for school routines, outings, and travel. children,kids food,school meals,family guidance,बच्चों का भोजन', '/article.html?type=food&slug=jain-food-for-children', 'Kids food', 'children,kids food,school meals,family guidance,बच्चों का भोजन', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-festival-fasting-food-guidance', 'food', 'festival-fasting-food-guidance', 'Festival fasting food guidance', 'Food practices during festivals and fasting may vary by family guidance, tradition, and individual capacity.', 'food Food practices during festivals and fasting may vary by family guidance, tradition, and individual capacity. Light permitted foods, fruit, limited preparation, and options guided by local practice For stricter observance, family elders, teachers, or local sangh guidance may be more helpful than a generic summary. Many people understand fasting as a discipline of restraint, reflection, and self-observation. Simple planning and lighter preparation can reduce stress during observance days. fasting,festival food,upvas,guidance,उपवास', '/article.html?type=food&slug=festival-fasting-food-guidance', 'Fasting', 'fasting,festival food,upvas,guidance,उपवास', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-ayambil-basics', 'food', 'ayambil-basics', 'Ayambil basics', 'Ayambil is often associated with simplicity in food, restraint, and spiritual attentiveness.', 'food Ayambil is often associated with simplicity in food, restraint, and spiritual attentiveness. Simple permitted ingredients, minimal seasoning, and restrained preparation The exact discipline and method may vary across traditions and family practice. Many people connect this practice with sensory restraint and inward simplicity. Simpler preparation can make the day feel more focused and deliberate. ayambil,fasting,discipline,simple food,आयंबिल', '/article.html?type=food&slug=ayambil-basics', 'Fasting', 'ayambil,fasting,discipline,simple food,आयंबिल', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-simple-jain-kitchen-discipline', 'food', 'simple-jain-kitchen-discipline', 'Simple Jain kitchen discipline', 'Many families treat kitchen cleanliness, minimal waste, simplicity, and clarity of ingredients as part of Jain discipline.', 'food Many families treat kitchen cleanliness, minimal waste, simplicity, and clarity of ingredients as part of Jain discipline. Small planning steps, fresh ingredients, measured quantity, and modest preparation can be helpful. Care and restraint around food are often treated as a practical extension of Jain values. An organized kitchen can help families manage time, cost, and wastage more effectively. kitchen discipline,daily routine,simple cooking,रसोई अनुशासन', '/article.html?type=food&slug=simple-jain-kitchen-discipline', 'Daily discipline', 'kitchen discipline,daily routine,simple cooking,रसोई अनुशासन', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-reading-packaged-food-labels', 'food', 'reading-packaged-food-labels', 'Reading packaged food labels', 'Reading ingredients, additives, and unclear terms on packaged food can be a useful skill for Jain families.', 'food Reading ingredients, additives, and unclear terms on packaged food can be a useful skill for Jain families. If an ingredient is unclear, it is usually better to check a trusted source or the manufacturer''s own information. Ingredient awareness can become one practical way of living food discipline more carefully. Label-reading can also help with identifying allergens, additives, and unwanted ingredients. packaged food,labels,ingredients,shopping,लेबल पढ़ना', '/article.html?type=food&slug=reading-packaged-food-labels', 'Daily diet', 'packaged food,labels,ingredients,shopping,लेबल पढ़ना', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-jain-food-during-travel-abroad', 'food', 'jain-food-during-travel-abroad', 'Jain food during travel abroad', 'During overseas travel, advance planning, simple choices, and polite communication can be helpful for many families.', 'food During overseas travel, advance planning, simple choices, and polite communication can be helpful for many families. Fruit, bread alternatives, plain grains, packaged fallback snacks, and simple cooked foods When menus are unfamiliar or language is a barrier, simpler options with fewer ingredients may be easier to verify. Maintaining awareness and restraint while traveling remains important for many Jain families. Advance planning can reduce dependence on uncertain food choices. travel abroad,foreign travel,jain food,packing,विदेश यात्रा भोजन', '/article.html?type=food&slug=jain-food-during-travel-abroad', 'Travel food', 'travel abroad,foreign travel,jain food,packing,विदेश यात्रा भोजन', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-family-friendly-jain-meal-planning', 'food', 'family-friendly-jain-meal-planning', 'Family-friendly Jain meal planning', 'When planning meals for a family, it can help to balance simplicity, children''s needs, elder guidance, and time discipline.', 'food When planning meals for a family, it can help to balance simplicity, children''s needs, elder guidance, and time discipline. A simple weekly list, seasonal vegetables, permitted staples, fruit, and light snacks A little advance planning can reduce rushed choices and make meals calmer for the whole family. Careful planning can support both awareness and cooperation within the family. Planned meals can make it easier to manage time, cost, and food wastage. family meal planning,daily diet,children,elders,भोजन योजना', '/article.html?type=food&slug=family-friendly-jain-meal-planning', 'Daily diet', 'family meal planning,daily diet,children,elders,भोजन योजना', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
