INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-jain-scholarship-guidance', 'resources', 'jain-scholarship-guidance', 'Jain scholarship guidance', 'A careful starting point for families and students who want to understand how to verify scholarship information without assuming current benefits or approval.', 'resources A careful starting point for families and students who want to understand how to verify scholarship information without assuming current benefits or approval. छात्रों और परिवारों के लिए एक सावधान प्रारंभिक मार्गदर्शिका, जिससे वे बिना अनुमान लगाए छात्रवृत्ति जानकारी की सत्यता जाँच सकें। Eligibility varies by provider, year, state, institution type, and current official notice. Helps students begin careful research before relying on secondary summaries. Use only the current official notice to confirm final document requirements. Scholarship India', '/resources.html', 'Scholarship', 'India', 'en', 'published', 'verified', 'JainWorld reviewed guide', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-minority-scholarship-document-checklist', 'resources', 'minority-scholarship-document-checklist', 'Minority scholarship document checklist', 'A practical pre-application checklist covering the kinds of documents many scholarship processes may request.', 'resources A practical pre-application checklist covering the kinds of documents many scholarship processes may request. आवेदन से पहले उपयोगी दस्तावेज़ों की एक व्यवहारिक सूची, जो कई छात्रवृत्ति प्रक्रियाओं में काम आ सकती है। Useful for students, parents, volunteers, and application helpers. Can reduce delays by helping families collect likely paperwork early. Photo ID, address proof, marksheets, bank details, income records, photographs, and institution documents may be required depending on the scheme. Documents / How-to Guide India', '/resources.html', 'Documents / How-to Guide', 'India', 'en', 'published', 'verified', 'JainWorld reviewed checklist', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-government-minority-resources-guide', 'resources', 'government-minority-resources-guide', 'Government minority resources guide', 'A cautious guide to identifying official portals, current notices, and the right authority before trusting a summary about a scheme.', 'resources A cautious guide to identifying official portals, current notices, and the right authority before trusting a summary about a scheme. किसी योजना के सारांश पर भरोसा करने से पहले आधिकारिक पोर्टल, वर्तमान नोटिस और सही प्राधिकरण पहचानने की सावधान मार्गदर्शिका। For anyone trying to verify whether a scheme or notice is official and current. Encourages users to depend on official notifications rather than assumptions. No fixed documents for this guide. Always use the relevant official notification. Government Scheme India', '/resources.html', 'Government Scheme', 'India', 'en', 'published', 'verified', 'JainWorld reviewed guide', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-jain-educational-institutions-directory-placeholder', 'resources', 'jain-educational-institutions-directory-placeholder', 'Jain educational institutions directory placeholder', 'A placeholder structure for future verified listings of Jain schools, colleges, libraries, pathshalas, and study centers.', 'resources A placeholder structure for future verified listings of Jain schools, colleges, libraries, pathshalas, and study centers. जैन विद्यालयों, महाविद्यालयों, पुस्तकालयों, पाठशालाओं और अध्ययन केंद्रों की भविष्य की सत्यापित सूची के लिए एक प्लेसहोल्डर संरचना। Useful for students, parents, and researchers exploring institution types. Supports future verified discovery without claiming complete or current listings today. Directory browsing does not require documents. Individual institutions may ask for their own admission materials. Educational Institution India', '/resources.html', 'Educational Institution', 'India', 'en', 'published', 'needs_review', 'Directory in progress', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-jain-hostels-and-dharamshala-directory-placeholder', 'resources', 'jain-hostels-and-dharamshala-directory-placeholder', 'Jain hostels and dharamshala directory placeholder', 'A placeholder for future verified city-wise references to Jain hostels, student accommodation, and dharamshala-related support.', 'resources A placeholder for future verified city-wise references to Jain hostels, student accommodation, and dharamshala-related support. जैन छात्रावास, छात्र आवास और धर्मशाला-संबंधी सहायता की भविष्य की सत्यापित नगर-वार सूची के लिए प्लेसहोल्डर। Availability depends on location, institution, and local rules. Helps users understand what kinds of entries JainWorld plans to verify over time. Please verify any hostel or stay-related requirements directly with the relevant office. Student Hostel India', '/resources.html', 'Student Hostel', 'India', 'en', 'published', 'needs_review', 'Directory in progress', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-jain-trusts-and-community-support-directory-placeholder', 'resources', 'jain-trusts-and-community-support-directory-placeholder', 'Jain trusts and community support directory placeholder', 'A safe placeholder for future verified listings of Jain trusts, charities, seva groups, and community support references.', 'resources A safe placeholder for future verified listings of Jain trusts, charities, seva groups, and community support references. जैन ट्रस्ट, चैरिटी, सेवा समूह और सामुदायिक सहायता संदर्भों की भविष्य की सत्यापित सूची के लिए सुरक्षित प्लेसहोल्डर। Support depends on the trust, location, and the type of help being requested. Sets expectations for future verified directory work without claiming completeness today. Any required documents will depend on the organization and support context. Jain Trust / NGO India / Global', '/resources.html', 'Jain Trust / NGO', 'India / Global', 'en', 'published', 'needs_review', 'Directory in progress', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-how-to-verify-official-scheme-links', 'resources', 'how-to-verify-official-scheme-links', 'How to verify official scheme links', 'A practical guide to checking whether a scheme link, notice, or portal is official before sharing it with students or families.', 'resources A practical guide to checking whether a scheme link, notice, or portal is official before sharing it with students or families. छात्रों या परिवारों के साथ साझा करने से पहले यह जांचने की व्यवहारिक मार्गदर्शिका कि कोई योजना लिंक, नोटिस या पोर्टल आधिकारिक है या नहीं। Useful for students, parents, volunteers, and resource curators. Reduces confusion and discourages reliance on outdated or unofficial pages. No fixed documents for this guide. Documents / How-to Guide India', '/resources.html', 'Documents / How-to Guide', 'India', 'en', 'published', 'verified', 'JainWorld reviewed guide', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-how-to-submit-a-resource-correction', 'resources', 'how-to-submit-a-resource-correction', 'How to submit a resource correction', 'A simple guide explaining what details help JainWorld review a resource update, broken link, or outdated note.', 'resources A simple guide explaining what details help JainWorld review a resource update, broken link, or outdated note. एक सरल मार्गदर्शिका जो बताती है कि संसाधन अपडेट, टूटा हुआ लिंक या पुरानी जानकारी भेजते समय कौन से विवरण उपयोगी होते हैं। Open to students, families, institutions, and volunteers who want to improve public resource quality. Helps the public corrections workflow stay clearer and more useful over time. Please include the page title, the issue noticed, and the best official source link if available. Documents / How-to Guide Global', '/resources.html', 'Documents / How-to Guide', 'Global', 'en', 'published', 'verified', 'JainWorld corrections workflow', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-student-support-resources', 'resources', 'student-support-resources', 'Student support resources', 'A broad reference entry covering the kinds of support students may look for, such as scholarships, hostels, study centers, and trusted guidance.', 'resources A broad reference entry covering the kinds of support students may look for, such as scholarships, hostels, study centers, and trusted guidance. एक व्यापक संदर्भ प्रविष्टि जिसमें छात्रवृत्ति, छात्रावास, अध्ययन केंद्र और विश्वसनीय मार्गदर्शन जैसे छात्र सहायता विषय शामिल हैं। Useful for students and guardians planning educational support research. Helps users think in categories before searching for specific verified sources. Documents vary by service and provider. Student Support India / Global', '/resources.html', 'Student Support', 'India / Global', 'en', 'published', 'curated', 'JainWorld learning reference', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-family-support-resources', 'resources', 'family-support-resources', 'Family support resources', 'A broad family-oriented reference for users seeking practical community, educational, and temple-linked support pathways.', 'resources A broad family-oriented reference for users seeking practical community, educational, and temple-linked support pathways. व्यावहारिक सामुदायिक, शैक्षणिक और मंदिर-संबंधी सहायता मार्ग खोजने वाले उपयोगकर्ताओं के लिए परिवार-केंद्रित संदर्भ प्रविष्टि। Useful for families, caregivers, volunteers, and community organizers. Supports safer planning by encouraging users to verify each official source before acting on it. Requirements vary by organization and service. Family Support India / Global', '/resources.html', 'Family Support', 'India / Global', 'en', 'published', 'curated', 'JainWorld learning reference', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-paryushan-learning', 'calendar', 'paryushan-learning', 'Paryushan', 'A major Jain festival period focused on introspection, restraint, prayer, forgiveness, and careful self-review.', 'calendar Paryushan पर्युषण A major Jain festival period focused on introspection, restraint, prayer, forgiveness, and careful self-review. आत्मचिंतन, संयम, प्रार्थना, क्षमा और सावधान आत्म-परीक्षण पर केंद्रित प्रमुख जैन पर्व काल। festival Bhadrapada भाद्रपद needs_review समीक्षा आवश्यक general global Educational overview only. Exact observance dates should be verified with a trusted panchang or local sangh. यह केवल शैक्षणिक जानकारी है। सही पालन तिथि विश्वसनीय पंचांग या स्थानीय संघ से सत्यापित करें। Dates can vary by panchang, tradition, and local sangh practice. तिथियाँ पंचांग, परंपरा और स्थानीय संघ की परंपरा के अनुसार भिन्न हो सकती हैं। Paryushan पर्युषण forgiveness fasting reflection', '/calendar.html', 'festival', 'festival, Bhadrapada, needs_review, general, global, Paryushan, पर्युषण, forgiveness, fasting, reflection', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-samvatsari-learning', 'calendar', 'samvatsari-learning', 'Samvatsari', 'A deeply reflective Jain observance associated with forgiveness, humility, and spiritual renewal.', 'calendar Samvatsari संवत्सरी A deeply reflective Jain observance associated with forgiveness, humility, and spiritual renewal. क्षमा, विनम्रता और आध्यात्मिक नवचिंतन से जुड़ा अत्यंत महत्वपूर्ण जैन पालन। festival Bhadrapada भाद्रपद needs_review समीक्षा आवश्यक general global Educational overview only. Community observance timing may vary locally. यह केवल शैक्षणिक जानकारी है। समुदाय अनुसार पालन का समय अलग हो सकता है। Please verify observance details with local sangh guidance. पालन का विवरण स्थानीय संघ के मार्गदर्शन से सत्यापित करें। Samvatsari संवत्सरी Micchami Dukkadam forgiveness', '/calendar.html', 'festival', 'festival, Bhadrapada, needs_review, general, global, Samvatsari, संवत्सरी, Micchami Dukkadam, forgiveness', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-das-lakshan-learning', 'calendar', 'das-lakshan-learning', 'Das Lakshan', 'A devotional period that encourages reflection on core virtues and disciplined spiritual practice.', 'calendar Das Lakshan दशलक्षण A devotional period that encourages reflection on core virtues and disciplined spiritual practice. मुख्य सद्गुणों और अनुशासित आध्यात्मिक अभ्यास पर मनन का भक्तिमय काल। festival Bhadrapada भाद्रपद needs_review समीक्षा आवश्यक digambar India Educational overview only. Tradition-specific dates should be checked carefully. यह केवल शैक्षणिक जानकारी है। परंपरा-विशिष्ट तिथियाँ सावधानी से जाँचें। Do not rely on one universal date for Das Lakshan observance. दशलक्षण पालन के लिए एक ही सार्वभौमिक तिथि पर निर्भर न रहें। Das Lakshan दशलक्षण Digambar virtues', '/calendar.html', 'festival', 'festival, Bhadrapada, needs_review, digambar, India, Das Lakshan, दशलक्षण, Digambar, virtues', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-mahavir-jayanti-learning', 'calendar', 'mahavir-jayanti-learning', 'Mahavir Jayanti', 'A festival remembering Bhagwan Mahavir and his teachings, often marked with local processions and sangh programmes.', 'calendar Mahavir Jayanti महावीर जयंती A festival remembering Bhagwan Mahavir and his teachings, often marked with local processions and sangh programmes. भगवान महावीर और उनकी शिक्षाओं की स्मृति का पर्व, जो कई स्थानों पर शोभायात्रा और संघ कार्यक्रमों से जुड़ा रहता है। festival Chaitra चैत्र shukla शुक्ल Trayodashi / verify locally त्रयोदशी / स्थानीय सत्यापन करें general global Use local temple and sangh guidance for exact observance details. सही पालन विवरण के लिए स्थानीय मंदिर और संघ मार्गदर्शन लें। Local programmes and procession timings can differ. स्थानीय कार्यक्रम और शोभायात्रा का समय भिन्न हो सकता है। Mahavir Jayanti महावीर जयंती Bhagwan Mahavir', '/calendar.html', 'festival', 'festival, Chaitra, Trayodashi / verify locally, shukla, general, global, Mahavir Jayanti, महावीर जयंती, Bhagwan Mahavir', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-ayambil-oli-learning', 'calendar', 'ayambil-oli-learning', 'Ayambil Oli', 'A period of disciplined food practice and devotional restraint observed in more than one season.', 'calendar Ayambil Oli आयंबिल ओली A period of disciplined food practice and devotional restraint observed in more than one season. अनुशासित आहार और भक्तिपूर्ण संयम का पालन, जो वर्ष में एक से अधिक बार मनाया जाता है। ayambil Chaitra / Ashwin चैत्र / आश्विन needs_review समीक्षा आवश्यक general India Local calendar and family guidance should be checked for the observance window. पालन अवधि के लिए स्थानीय कैलेंडर और पारिवारिक मार्गदर्शन देखें। Please verify the observance window with local guidance. पालन की अवधि स्थानीय मार्गदर्शन से सत्यापित करें। Ayambil Oli आयंबिल ओली fasting discipline', '/calendar.html', 'ayambil', 'ayambil, Chaitra / Ashwin, needs_review, general, India, Ayambil Oli, आयंबिल ओली, fasting, discipline', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-kartik-purnima-learning', 'calendar', 'kartik-purnima-learning', 'Kartik Purnima', 'An observance remembered in different local ways, often linked with temple visits and devotional reflection.', 'calendar Kartik Purnima कार्तिक पूर्णिमा An observance remembered in different local ways, often linked with temple visits and devotional reflection. विभिन्न स्थानीय परंपराओं में स्मरण किया जाने वाला पालन, जो कई जगह मंदिर दर्शन और मनन से जुड़ता है। festival Kartik कार्तिक shukla शुक्ल Purnima / verify locally पूर्णिमा / स्थानीय सत्यापन करें general India Temple or tirth programme timings should always be checked locally. मंदिर या तीर्थ कार्यक्रम का समय स्थानीय रूप से जाँचें। Local programmes and observance details can vary. स्थानीय कार्यक्रम और पालन का विवरण भिन्न हो सकता है। Kartik Purnima कार्तिक पूर्णिमा temple visit', '/calendar.html', 'festival', 'festival, Kartik, Purnima / verify locally, shukla, general, India, Kartik Purnima, कार्तिक पूर्णिमा, temple visit', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-akshaya-tritiya-learning', 'calendar', 'akshaya-tritiya-learning', 'Akshaya Tritiya', 'Observed with different layers of meaning in Jain tradition, often linked with restraint, charity, and spiritual remembrance.', 'calendar Akshaya Tritiya अक्षय तृतीया Observed with different layers of meaning in Jain tradition, often linked with restraint, charity, and spiritual remembrance. जैन परंपरा में संयम, दान और आध्यात्मिक स्मरण से जुड़ा पालन, जिसका महत्व अलग-अलग समुदायों में भिन्न रूप से समझा जा सकता है। festival Vaishakh वैशाख shukla शुक्ल Tritiya / verify locally तृतीया / स्थानीय सत्यापन करें general India General learning entry only. Exact observance dates need local confirmation. यह सामान्य शैक्षणिक प्रविष्टि है। सही पालन तिथि स्थानीय रूप से सत्यापित करें। Festival dates may vary by panchang and location. पर्व की तिथियाँ पंचांग और स्थान के अनुसार भिन्न हो सकती हैं। Akshaya Tritiya अक्षय तृतीया charity', '/calendar.html', 'festival', 'festival, Vaishakh, Tritiya / verify locally, shukla, general, India, Akshaya Tritiya, अक्षय तृतीया, charity', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-diwali-jain-learning', 'calendar', 'diwali-jain-learning', 'Diwali in Jain tradition', 'In Jain tradition, Diwali is linked with deep spiritual remembrance and reflective observance.', 'calendar Diwali in Jain tradition जैन परंपरा में दिवाली In Jain tradition, Diwali is linked with deep spiritual remembrance and reflective observance. जैन परंपरा में दिवाली गहरे आध्यात्मिक स्मरण और मननपूर्ण पालन से जुड़ी है। festival Kartik कार्तिक krishna कृष्ण Amavasya / verify locally अमावस्या / स्थानीय सत्यापन करें general global Local temple programmes and observance schedules should be verified locally. स्थानीय मंदिर कार्यक्रम और पालन समय स्थानीय रूप से जाँचें। Please verify local sangh and temple schedules before attending. उपस्थित होने से पहले स्थानीय संघ और मंदिर का कार्यक्रम सत्यापित करें। Diwali दिवाली Jain tradition', '/calendar.html', 'festival', 'festival, Kartik, Amavasya / verify locally, krishna, general, global, Diwali, दिवाली, Jain tradition', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-rohini-vrat-learning', 'calendar', 'rohini-vrat-learning', 'Rohini Vrat', 'A vrat observed in many Jain families with local calendar variation and family guidance.', 'calendar Rohini Vrat रोहिणी व्रत A vrat observed in many Jain families with local calendar variation and family guidance. अनेक जैन परिवारों में मनाया जाने वाला व्रत, जिसकी तिथि स्थानीय कैलेंडर और पारिवारिक मार्गदर्शन पर निर्भर हो सकती है। vrat needs_review समीक्षा आवश्यक general local Specific observance dates should be confirmed through a trusted Jain panchang. विशिष्ट पालन तिथियों की पुष्टि विश्वसनीय जैन पंचांग से करें। Do not rely on a placeholder date for Rohini Vrat observance. रोहिणी व्रत के पालन के लिए किसी नमूना तिथि पर निर्भर न रहें। Rohini Vrat रोहिणी व्रत vrat', '/calendar.html', 'vrat', 'vrat, needs_review, general, local, Rohini Vrat, रोहिणी व्रत, vrat', 'en', 'published', 'published', 'JainWorld manual educational review', '2026-05-27', '2026-05-27', 3, '2026-05-27');
